H_upper = rho0 * cp0 * (nemo["gridT/thetao_con"]
                        .sel(time_counter=slice("2020-01", "2024-01"))
                        .apply_mask(pacmask, drop=True)
                        .depth_integral(limits=(0, 500))
                        .integral(dims=["i", "j"])
                        )

